352	    /// Returns `true` if the queue is empty.
353	    ///
354	    /// ```
355	    /// use crossbeam_deque::Worker;
356	    ///
357	    /// let w = Worker::new_lifo();
358	    ///
359	    /// assert!(w.is_empty());
360	    /// w.push(1);
361	    /// assert!(!w.is_empty());
362	    /// ```
363	    pub fn is_empty(&self) -> bool {
364	        let b = self.inner.back.load(Ordering::Relaxed);
365	        let f = self.inner.front.load(Ordering::SeqCst);
366	        b.wrapping_sub(f) <= 0
367	    }
368	
369	    /// Returns the number of tasks in the deque.
370	    ///
371	    /// ```
372	    /// use crossbeam_deque::Worker;
373	    ///
374	    /// let w = Worker::new_lifo();
375	    ///
376	    /// assert_eq!(w.len(), 0);
377	    /// w.push(1);
378	    /// assert_eq!(w.len(), 1);
379	    /// w.push(1);
380	    /// assert_eq!(w.len(), 2);
381	    /// ```
382	    pub fn len(&self) -> usize {
383	        let b = self.inner.back.load(Ordering::Relaxed);
384	        let f = self.inner.front.load(Ordering::SeqCst);
385	        b.wrapping_sub(f).max(0) as usize
386	    }
387	
388	    /// Pushes a task into the queue.
389	    ///
390	    /// # Examples
391	    ///
392	    /// ```
393	    /// use crossbeam_deque::Worker;
394	    ///
395	    /// let w = Worker::new_lifo();
396	    /// w.push(1);
397	    /// w.push(2);
398	    /// ```
399	    pub fn push(&self, task: T) {
400	        // Load the back index, front index, and buffer.
401	        let b = self.inner.back.load(Ordering::Relaxed);
402	        let f = self.inner.front.load(Ordering::Acquire);
403	        let mut buffer = self.buffer.get();
404	
405	        // Calculate the length of the queue.
406	        let len = b.wrapping_sub(f);
407	
408	        // Is the queue full?
409	        if len >= buffer.cap as isize {
410	            // Yes. Grow the underlying buffer.
411	            unsafe {
412	                self.resize(2 * buffer.cap);
413	            }
414	            buffer = self.buffer.get();
415	        }
416	
417	        // Write `task` into the slot.
418	        unsafe {
419	            buffer.write(b, MaybeUninit::new(task));
420	        }
421	
422	        // ThreadSanitizer does not understand fences, so we omit fence and do store with Release ordering.
423	        #[cfg(not(crossbeam_sanitize_thread))]
424	        atomic::fence(Ordering::Release);
425	        let store_order = if cfg!(crossbeam_sanitize_thread) {
426	            Ordering::Release
427	        } else {
428	            Ordering::Relaxed
429	        };
430	
431	        // Increment the back index.
432	        self.inner.back.store(b.wrapping_add(1), store_order);
433	    }
434	
435	    /// Pops a task from the queue.
436	    ///
437	    /// # Examples
438	    ///
439	    /// ```
440	    /// use crossbeam_deque::Worker;
441	    ///
442	    /// let w = Worker::new_fifo();
443	    /// w.push(1);
444	    /// w.push(2);
445	    ///
446	    /// assert_eq!(w.pop(), Some(1));
447	    /// assert_eq!(w.pop(), Some(2));
448	    /// assert_eq!(w.pop(), None);
449	    /// ```
450	    pub fn pop(&self) -> Option<T> {
451	        // Load the back and front index.
452	        let b = self.inner.back.load(Ordering::Relaxed);
453	        let f = self.inner.front.load(Ordering::Relaxed);
454	
455	        // Calculate the length of the queue.
456	        let len = b.wrapping_sub(f);
457	
458	        // Is the queue empty?
459	        if len <= 0 {
460	            return None;
461	        }
462	
463	        match self.flavor {
464	            // Pop from the front of the queue.
465	            Flavor::Fifo => {
466	                // Try incrementing the front index to pop the task.
467	                let f = self.inner.front.fetch_add(1, Ordering::SeqCst);
468	                let new_f = f.wrapping_add(1);
469	
470	                if b.wrapping_sub(new_f) < 0 {
471	                    self.inner.front.store(f, Ordering::Relaxed);
472	                    return None;
473	                }
474	
475	                unsafe {
476	                    // Read the popped task.
477	                    let buffer = self.buffer.get();
478	                    let task = buffer.read(f).assume_init();
479	
480	                    // Shrink the buffer if `len - 1` is less than one fourth of the capacity.
481	                    if buffer.cap > MIN_CAP && len <= buffer.cap as isize / 4 {
482	                        self.resize(buffer.cap / 2);
483	                    }
484	
485	                    Some(task)
486	                }
487	            }
488	
489	            // Pop from the back of the queue.
490	            Flavor::Lifo => {
491	                // Decrement the back index.
492	                let b = b.wrapping_sub(1);
493	                self.inner.back.store(b, Ordering::Relaxed);
494	
495	                atomic::fence(Ordering::SeqCst);
496	
497	                // Load the front index.
498	                let f = self.inner.front.load(Ordering::Relaxed);
499	
500	                // Compute the length after the back index was decremented.
501	                let len = b.wrapping_sub(f);
502	
503	                if len < 0 {
504	                    // The queue is empty. Restore the back index to the original task.
505	                    self.inner.back.store(b.wrapping_add(1), Ordering::Relaxed);
506	                    None
507	                } else {
508	                    // Read the task to be popped.
509	                    let buffer = self.buffer.get();
510	                    let mut task = unsafe { Some(buffer.read(b)) };
511	
512	                    // Are we popping the last task from the queue?
513	                    if len == 0 {
514	                        // Try incrementing the front index.
515	                        if self
516	                            .inner
517	                            .front
518	                            .compare_exchange(
519	                                f,
520	                                f.wrapping_add(1),
521	                                Ordering::SeqCst,
522	                                Ordering::Relaxed,
523	                            )
524	                            .is_err()
525	                        {
526	                            // Failed. We didn't pop anything. Reset to `None`.
527	                            task.take();
528	                        }
529	
530	                        // Restore the back index to the original task.
531	                        self.inner.back.store(b.wrapping_add(1), Ordering::Relaxed);
532	                    } else {
533	                        // Shrink the buffer if `len` is less than one fourth of the capacity.
534	                        if buffer.cap > MIN_CAP && len < buffer.cap as isize / 4 {
535	                            unsafe {
536	                                self.resize(buffer.cap / 2);
537	                            }
538	                        }
539	                    }
540	
541	                    task.map(|t| unsafe { t.assume_init() })
542	                }
543	            }
544	        }
545	    }
546	}
