1232	/// A block in a linked list.
1233	///
1234	/// Each block in the list can hold up to `BLOCK_CAP` values.
1235	struct Block<T> {
1236	    /// The next block in the linked list.
1237	    next: AtomicPtr<Block<T>>,
1238	
1239	    /// Slots for values.
1240	    slots: [Slot<T>; BLOCK_CAP],
1241	}
