1271	    /// Waits until the next pointer is set.
1272	    fn wait_next(&self) -> *mut Self {
1273	        let backoff = Backoff::new();
1274	        loop {
1275	            let next = self.next.load(Ordering::Acquire);
1276	            if !next.is_null() {
1277	                return next;
1278	            }
1279	            backoff.snooze();
1280	        }
1281	    }
