1328	/// assert_eq!(q.steal(), Steal::Success(1));
1329	/// assert_eq!(q.steal(), Steal::Success(2));
1330	/// assert_eq!(q.steal(), Steal::Empty);
1331	/// ```
1332	pub struct Injector<T> {
1333	    /// The head of the queue.
1334	    head: CachePadded<Position<T>>,
1335	
1336	    /// The tail of the queue.
1337	    tail: CachePadded<Position<T>>,
1338	
1339	    /// Indicates that dropping a `Injector<T>` may drop values of type `T`.
1340	    _marker: PhantomData<T>,
1341	}
